# Instalar
npm install -D tailwindcss @tailwindcss/vite

# vite.config.ts — adicionar o plugin
import tailwindcss from '@tailwindcss/vite';
export default defineConfig({
  plugins: [react(), tailwindcss()],
});

# No seu CSS principal (ex: index.css)
@import "tailwindcss";

function UserCard({ nome, cargo, avatar }) {
  return (
    <div className="flex items-center gap-4 rounded-lg border border-gray-200 bg-white p-4 shadow-sm">
      <img
        src={avatar}
        alt={nome}
        className="size-12 rounded-full object-cover"
      />
      <div>
        <h3 className="text-lg font-semibold text-gray-900">{nome}</h3>
        <p className="text-sm text-gray-500">{cargo}</p>
      </div>
    </div>
  );
}

